const { ApolloServer } = require('@apollo/server');
const { startStandaloneServer } = require('@apollo/server/standalone');
const DataLoader = require('dataloader');

const typeDefs = `#graphql
  scalar DateTime

  type Query {
    users(limit: Int, offset: Int): [User!]!
    user(id: ID!): User
    posts(limit: Int, offset: Int): [Post!]!
    post(id: ID!): Post
    comments(limit: Int, offset: Int): [Comment!]!
    comment(id: ID!): Comment
    search(query: String!, limit: Int, offset: Int): SearchResult!
  }

  type SearchResult {
    users: [User!]!
    posts: [Post!]!
    comments: [Comment!]!
  }

  type User {
    id: ID!
    username: String!
    name: String
    createdAt: DateTime!

    posts(limit: Int, offset: Int): [Post!]!
    comments(limit: Int, offset: Int): [Comment!]!
  }

  type Post {
    id: ID!
    authorId: ID!
    author: User!
    body: String!
    createdAt: DateTime!

    comments(limit: Int, offset: Int): [Comment!]!
  }

  type Comment {
    id: ID!
    postId: ID!
    authorId: ID!
    author: User!
    post: Post!
    body: String!
    createdAt: DateTime!
  }
`;

function nowISO() {
  return new Date().toISOString();
}

function applyPagination(arr, limit, offset) {
  const o = Math.max(0, offset || 0);
  const l = limit == null ? arr.length : Math.max(0, limit);
  return arr.slice(o, o + l);
}

function containsCI(haystack, needle) {
  if (!needle) return true;
  const n = String(needle).toLowerCase();
  return String(haystack || '').toLowerCase().includes(n);
}

function seedData() {
  const users = [
    { id: 'u1', username: 'alex', name: 'Alex', createdAt: nowISO() },
    { id: 'u2', username: 'sam', name: 'Sam', createdAt: nowISO() },
    { id: 'u3', username: 'taylor', name: 'Taylor', createdAt: nowISO() },
  ];

  const posts = [
    { id: 'p1', authorId: 'u1', body: 'Hello world', createdAt: nowISO() },
    { id: 'p2', authorId: 'u2', body: 'GraphQL is neat', createdAt: nowISO() },
    { id: 'p3', authorId: 'u1', body: 'Nested relationships', createdAt: nowISO() },
    { id: 'p4', authorId: 'u3', body: 'Apollo Server in Node.js', createdAt: nowISO() },
  ];

  const comments = [
    { id: 'c1', postId: 'p1', authorId: 'u2', body: 'Nice post!', createdAt: nowISO() },
    { id: 'c2', postId: 'p1', authorId: 'u3', body: 'Welcome!', createdAt: nowISO() },
    { id: 'c3', postId: 'p2', authorId: 'u1', body: 'Agreed', createdAt: nowISO() },
    { id: 'c4', postId: 'p3', authorId: 'u2', body: 'Infinite nesting?', createdAt: nowISO() },
    { id: 'c5', postId: 'p4', authorId: 'u1', body: 'Love Apollo', createdAt: nowISO() },
  ];

  return { users, posts, comments };
}

function makeDB() {
  const { users, posts, comments } = seedData();

  const byId = (arr) => {
    const m = new Map();
    for (const x of arr) m.set(x.id, x);
    return m;
  };

  return {
    users,
    posts,
    comments,
    userById: byId(users),
    postById: byId(posts),
    commentById: byId(comments),
  };
}

function createLoaders(db) {
  const userById = new DataLoader(async (ids) => {
    return ids.map((id) => db.userById.get(String(id)) || null);
  });

  const postById = new DataLoader(async (ids) => {
    return ids.map((id) => db.postById.get(String(id)) || null);
  });

  const commentById = new DataLoader(async (ids) => {
    return ids.map((id) => db.commentById.get(String(id)) || null);
  });

  const postsByAuthorId = new DataLoader(async (authorIds) => {
    const grouped = new Map();
    for (const id of authorIds) grouped.set(String(id), []);
    for (const p of db.posts) {
      const k = String(p.authorId);
      if (grouped.has(k)) grouped.get(k).push(p);
    }
    return authorIds.map((id) => grouped.get(String(id)) || []);
  });

  const commentsByAuthorId = new DataLoader(async (authorIds) => {
    const grouped = new Map();
    for (const id of authorIds) grouped.set(String(id), []);
    for (const c of db.comments) {
      const k = String(c.authorId);
      if (grouped.has(k)) grouped.get(k).push(c);
    }
    return authorIds.map((id) => grouped.get(String(id)) || []);
  });

  const commentsByPostId = new DataLoader(async (postIds) => {
    const grouped = new Map();
    for (const id of postIds) grouped.set(String(id), []);
    for (const c of db.comments) {
      const k = String(c.postId);
      if (grouped.has(k)) grouped.get(k).push(c);
    }
    return postIds.map((id) => grouped.get(String(id)) || []);
  });

  return {
    userById,
    postById,
    commentById,
    postsByAuthorId,
    commentsByAuthorId,
    commentsByPostId,
  };
}

const resolvers = {
  DateTime: {
    __serialize(value) {
      if (value == null) return null;
      if (value instanceof Date) return value.toISOString();
      return String(value);
    },
  },

  Query: {
    users: async (_, { limit, offset }, { db }) => applyPagination(db.users, limit, offset),
    user: async (_, { id }, { loaders }) => loaders.userById.load(String(id)),
    posts: async (_, { limit, offset }, { db }) => applyPagination(db.posts, limit, offset),
    post: async (_, { id }, { loaders }) => loaders.postById.load(String(id)),
    comments: async (_, { limit, offset }, { db }) => applyPagination(db.comments, limit, offset),
    comment: async (_, { id }, { loaders }) => loaders.commentById.load(String(id)),
    search: async (_, { query, limit, offset }, { db }) => {
      const q = String(query || '');
      const users = db.users.filter((u) => containsCI(u.username, q) || containsCI(u.name, q));
      const posts = db.posts.filter((p) => containsCI(p.body, q));
      const comments = db.comments.filter((c) => containsCI(c.body, q));

      const lim = limit == null ? undefined : limit;
      const off = offset == null ? undefined : offset;

      return {
        users: applyPagination(users, lim, off),
        posts: applyPagination(posts, lim, off),
        comments: applyPagination(comments, lim, off),
      };
    },
  },

  User: {
    posts: async (user, { limit, offset }, { loaders }) => {
      const all = await loaders.postsByAuthorId.load(String(user.id));
      return applyPagination(all, limit, offset);
    },
    comments: async (user, { limit, offset }, { loaders }) => {
      const all = await loaders.commentsByAuthorId.load(String(user.id));
      return applyPagination(all, limit, offset);
    },
  },

  Post: {
    author: async (post, _, { loaders }) => loaders.userById.load(String(post.authorId)),
    comments: async (post, { limit, offset }, { loaders }) => {
      const all = await loaders.commentsByPostId.load(String(post.id));
      return applyPagination(all, limit, offset);
    },
  },

  Comment: {
    author: async (comment, _, { loaders }) => loaders.userById.load(String(comment.authorId)),
    post: async (comment, _, { loaders }) => loaders.postById.load(String(comment.postId)),
  },
};

async function main() {
  const db = makeDB();

  const server = new ApolloServer({
    typeDefs,
    resolvers,
  });

  const { url } = await startStandaloneServer(server, {
    listen: { port: Number(process.env.PORT || 4000) },
    context: async () => {
      const loaders = createLoaders(db);
      return { db, loaders };
    },
  });

  console.log(`GraphQL API ready at ${url}`);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});